1864	func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
1865		if asJSON {
1866			payload := struct {
1867				ProjectRoot string `json:"project_root"`
1868				*agent.ExecuteBeadLoopResult
1869			}{
1870				ProjectRoot:           projectRoot,
1871				ExecuteBeadLoopResult: result,
1872			}
1873			enc := json.NewEncoder(w)
1874			enc.SetIndent("", "  ")
1875			return enc.Encode(payload)
1876		}
1877	
1878		if result.NoReadyWork && result.Attempts == 0 {
1879			writeNoReadyWorkSummary(w, projectRoot, result.NoReadyWorkDetail)
1880			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1881			return nil
1882		}
1883	
1884		fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
1885		writeWorkTerminalSummary(w, result)
1886		if result.Failures > 0 {
1887			fmt.Fprintf(w, "\nfailed:\n")
1888			for _, attempt := range result.Results {
1889				if attempt.Status != "success" {
1890					fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
1891					if attempt.PreserveRef != "" {
1892						fmt.Fprintf(w, " (preserved)")
1893					}
1894					fmt.Fprintln(w)
1895				}
1896			}
1897		}
1898		if result.NoReadyWork {
1899			fmt.Fprintln(w)
1900			writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
1901			writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
1902		}
1903		return nil
